// Store DATA only — not functions (Node-RED function serialization issues)

global.set('MENU_KB', [
    [{ text: '➕ Додати', callback_data: 'menu_add' }, { text: '📋 Контакти', callback_data: 'menu_list' }],
    [{ text: '⏰ Найближчі', callback_data: 'menu_upcoming' }, { text: '❓ Допомога', callback_data: 'menu_help' }]
]);

global.set('BACK_KB', [[{ text: '🏠 Меню', callback_data: 'menu_home' }]]);

global.set('HELP_TEXT', [
    '<b>🎂 Birthday Reminder Bot</b>', '',
    'ДН близьких + AI-ідеї подарунків 🎁', '',
    '<b>🔹 Функції:</b>',
    '• Зберігаю контакти з ДН',
    '• Нагадую за 7, 3, 1 день та у день',
    '• AI-ідеї подарунків у гривнях',
    '• Памʼятаю інтереси', '',
    '<b>🗣 Пиши природньою мовою:</b>',
    '• «додай Петра 15.03.1990»',
    '• «коли у Олі ДН?»',
    '• «що подарувати Тарасу?»',
    '• «Петро любить футбол»',
    '• «розкажи про Марію»',
    '• «видали Дениса»',
    '• «найближчі ДН»', '',
    '<b>Команди:</b> /start /cancel /help'
].join('\n'));

node.warn('[INIT] MENU_KB, BACK_KB, HELP_TEXT registered');
return null;

const token = env.get('TELEGRAM_BOT_TOKEN');
if (!token) { node.error('TELEGRAM_BOT_TOKEN not set'); return null; }
const lastId = (msg.payload && msg.payload[0] && msg.payload[0].last_update_id) || 0;
const offset = Number(lastId) + 1;
msg.url = `${env.get('TELEGRAM_API_BASE')||'https://api.telegram.org'}/bot${token}/getUpdates?offset=${offset}&timeout=25&allowed_updates=["message","callback_query"]`;
msg.method = 'GET';
return msg;

const err = msg.error || {};
const code = err.code || '';
const ignoreList = ['ECONNRESET','ETIMEDOUT','ECONNREFUSED','ECONNABORTED','UND_ERR_SOCKET'];
if (ignoreList.includes(code) || /socket hang up|timeout/i.test(err.message || '')) {
    // Тихо — це нормально при long polling
    return null;
}
// Інші помилки — пропускаємо далі (у глобальний catch)
node.warn('HTTP error: ' + (err.message || code));
return null;

if (!msg.payload || msg.payload.ok !== true) {
    const code = msg.payload && msg.payload.error_code;

    if (code === 409) {
        // Мовчазно — тільки статус на ноді, без warn
        const count = (flow.get('conflictCount') || 0) + 1;
        flow.set('conflictCount', count);
        node.status({ fill: 'yellow', shape: 'ring', text: `409 conflict x${count}` });
        return null;
    }

    // Інші помилки — логуємо завжди
    node.warn('getUpdates failed: '+JSON.stringify(msg.payload));
    return null;
}

// Успіх — ресетимо
if (flow.get('conflictCount')) {
    flow.set('conflictCount', 0);
    node.status({ fill: 'green', shape: 'dot', text: 'polling ok' });
}

const updates = msg.payload.result || [];
if (updates.length === 0) return null;
msg.payload = updates;
return msg;

const update = msg.payload;
msg.update = update;
msg.updateId = update.update_id;
msg.query = 'INSERT INTO processed_updates (update_id) VALUES ($1) ON CONFLICT DO NOTHING RETURNING update_id';
msg.params = [update.update_id];
return msg;

const isNew = Array.isArray(msg.payload) && msg.payload.length > 0;
if (!isNew) { node.log(`Update ${msg.updateId} already processed`); return null; }
msg.payload = msg.update;
return [msg, { updateId: msg.updateId }];

msg.query = 'UPDATE bot_offset SET last_update_id = $1, updated_at = NOW() WHERE id = 1 AND last_update_id < $1';
msg.params = [msg.updateId];
return msg;

const update = msg.payload;
let from, chatId, messageType, text, contact, callbackData, messageId;

if (update.callback_query) {
    from = update.callback_query.from;
    chatId = update.callback_query.message.chat.id;
    messageType = 'callback';
    callbackData = update.callback_query.data;
    messageId = update.callback_query.message.message_id;
    msg.callbackQueryId = update.callback_query.id;
} else if (update.message) {
    from = update.message.from;
    chatId = update.message.chat.id;
    if (update.message.contact) { messageType = 'contact'; contact = update.message.contact; }
    else if (update.message.text) { text = update.message.text.trim(); messageType = text.startsWith('/') ? 'command' : 'text'; }
    else { messageType = 'other'; }
    messageId = update.message.message_id;
} else { node.warn('Unknown update type'); return null; }

msg.from = from; msg.chatId = chatId; msg.userId = from.id;
msg.messageType = messageType; msg.text = text; msg.contact = contact;
msg.callbackData = callbackData; msg.messageId = messageId;

msg.query = 'SELECT state, context FROM user_sessions WHERE telegram_id = $1';
msg.params = [from.id];
return msg;

const rows = msg.payload || [];
msg.session = rows.length ? { state: rows[0].state, context: rows[0].context } : { state: 'idle', context: null };
return msg;

const parts = msg.text.split(/\s+/);
const cmd = parts[0].toLowerCase().split('@')[0];
msg.command = cmd;
msg.args = parts.slice(1);
return msg;

msg.query = `INSERT INTO users (telegram_id, username, first_name, last_name, language_code) VALUES ($1,$2,$3,$4,$5) ON CONFLICT (telegram_id) DO UPDATE SET username=EXCLUDED.username, first_name=EXCLUDED.first_name, last_name=EXCLUDED.last_name, language_code=EXCLUDED.language_code, is_active=TRUE RETURNING telegram_id, first_name, phone_number`;
msg.params = [
    msg.from.id,
    msg.from.username || null,
    msg.from.first_name || msg.from.username || 'User',
    msg.from.last_name || null,
    msg.from.language_code || null
];
return msg;

msg.userRow = msg.payload[0];
msg.query = `INSERT INTO user_sessions (telegram_id, state, context) VALUES ($1,'idle',NULL) ON CONFLICT (telegram_id) DO UPDATE SET state='idle', context=NULL`;
msg.params = [msg.from.id];
return msg;

function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
const mainMenu = global.get('MENU_KB');
const hasPhone = msg.userRow && msg.userRow.phone_number;
const firstName = msg.userRow ? msg.userRow.first_name : 'друже';
const photoUrl = env.get('MENU_PHOTO_URL');

msg.auditAction = 'user_registered';
msg.auditPayload = { username: msg.from.username };

if (!hasPhone) {
    msg.tgMethod = 'sendMessage';
    msg.tgBody = {
        chat_id: msg.chatId,
        text: `👋 Привіт, <b>${esc(firstName)}</b>!\n\n🎂 Я — твій особистий нагадувач про дні народження.\n\n<b>✨ Що я вмію:</b>\n• Зберігати ДН близьких\n• Нагадувати за 7, 3, 1 день та у день\n• Підбирати ідеї подарунків з AI\n• Памʼятати інтереси кожного\n\n<b>💬 Найкраще — просто пиши як людині:</b>\n<i>«додай Олю 15 березня 1990»</i>\n<i>«що подарувати Петру?»</i>\n\n📱 Для початку поділись контактом:`,
        parse_mode: 'HTML',
        reply_markup: {
            keyboard: [[{ text: '📱 Поділитись контактом', request_contact: true }]],
            resize_keyboard: true,
            one_time_keyboard: true
        }
    };
} else {
    const caption = [
        `👋 З поверненням, <b>${esc(firstName)}</b>!`,
        '',
        '💬 <b>Нагадую — пиши як людині:</b>',
        '<i>«додай Олю 15 березня 1990»</i>',
        '<i>«що подарувати Петру?»</i>',
        '<i>«коли у Марії ДН?»</i>',
        '<i>«Петро фанат футболу»</i>',
        '',
        '📋 Або обирай дію з меню ⬇️'
    ].join('\n');
    if (photoUrl) {
        msg.tgMethod = 'sendPhoto';
        msg.tgBody = { chat_id: msg.chatId, photo: photoUrl, caption, parse_mode: 'HTML', reply_markup: { inline_keyboard: mainMenu } };
    } else {
        msg.tgMethod = 'sendMessage';
        msg.tgBody = { chat_id: msg.chatId, text: caption, parse_mode: 'HTML', reply_markup: { inline_keyboard: mainMenu } };
    }
}

return msg;

function buildReply(o){
  const b = { chat_id: o.chatId, parse_mode: "HTML" };
  if (o.useEdit && o.messageId) b.message_id = o.messageId;
  if (o.useEdit && o.photo) return { method: "editMessageMedia", body: Object.assign(b, { media: { type:"photo", media: o.photo, caption: o.text, parse_mode: "HTML" }, reply_markup: { inline_keyboard: o.keyboard } }) };
  if (o.useEdit) return { method: "editMessageText", body: Object.assign(b, { text: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
  if (o.photo) return { method: "sendPhoto", body: Object.assign(b, { photo: o.photo, caption: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
  return { method: "sendMessage", body: Object.assign(b, { text: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
}
const reply = buildReply({
    chatId: msg.chatId,
    photo: env.get('MENU_PHOTO_HELP'),
    text: global.get('HELP_TEXT'),
    keyboard: global.get('BACK_KB')
});
msg.tgMethod = reply.method;
msg.tgBody = reply.body;
return msg;

msg.query = `UPDATE user_sessions SET state='idle', context=NULL WHERE telegram_id=$1`;
msg.params = [msg.from.id];
msg._useEdit = false;
return msg;

msg.tgMethod = 'sendMessage';
msg.tgBody = { chat_id: msg.chatId, text: 'Не знаю такої команди. Просто напиши що тобі треба природньою мовою — я зрозумію 😊' };
return msg;

const contact = msg.contact;
if (contact.user_id !== msg.from.id) {
    msg.tgMethod='sendMessage';
    msg.tgBody={chat_id:msg.chatId,text:'Будь ласка, поділись <b>своїм</b> контактом.',parse_mode:'HTML'};
    return [null, msg];
}
msg.query = 'UPDATE users SET phone_number=$1 WHERE telegram_id=$2 RETURNING first_name';
msg.params = [contact.phone_number, msg.from.id];
return [msg, null];

function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
const name = msg.payload && msg.payload[0] ? msg.payload[0].first_name : 'друже';

msg.tgMethod = 'sendMessage';
msg.tgBody = {
    chat_id: msg.chatId,
    text: `🎉 Чудово, <b>${esc(name)}</b>! Реєстрація завершена.`,
    parse_mode: 'HTML',
    reply_markup: { remove_keyboard: true }
};

msg._followup = {
    chat_id: msg.chatId,
    text: [
        '🎓 <b>Як користуватись ботом</b>',
        '',
        '💬 <b>Спілкуйся як з людиною</b> — просто пиши що треба:',
        '',
        '📝 <b>Додати контакт:</b>',
        '<i>«додай Олю 15 березня 1990, любить книги»</i>',
        '',
        '🎂 <b>Запитати про ДН:</b>',
        '<i>«коли у Марії ДН?»</i>',
        '',
        '🎁 <b>AI підбере подарунок:</b>',
        '<i>«що подарувати Петру?»</i>',
        '',
        '💡 <b>Додати інтереси пізніше:</b>',
        '<i>«Петро фанат футболу»</i>',
        '',
        '📋 Або використовуй кнопки меню ⬇️'
    ].join('\n'),
    parse_mode: 'HTML',
    reply_markup: { inline_keyboard: global.get('MENU_KB') }
};
msg.auditAction = 'contact_shared';
return msg;

if (!msg._followup) return null;
const m = { tgMethod:'sendMessage', tgBody: msg._followup, chatId: msg.chatId };
return m;

const ack = { tgMethod:'answerCallbackQuery', tgBody:{ callback_query_id: msg.callbackQueryId } };
msg._useEdit = true;  // всі callbacks редагують існуюче повідомлення
return [ack, msg];

function buildReply(o){
  const b = { chat_id: o.chatId, parse_mode: "HTML" };
  if (o.useEdit && o.messageId) b.message_id = o.messageId;
  if (o.useEdit && o.photo) return { method: "editMessageMedia", body: Object.assign(b, { media: { type:"photo", media: o.photo, caption: o.text, parse_mode: "HTML" }, reply_markup: { inline_keyboard: o.keyboard } }) };
  if (o.useEdit) return { method: "editMessageText", body: Object.assign(b, { text: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
  if (o.photo) return { method: "sendPhoto", body: Object.assign(b, { photo: o.photo, caption: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
  return { method: "sendMessage", body: Object.assign(b, { text: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
}
const reply = buildReply({
    chatId: msg.chatId,
    messageId: msg.messageId,
    useEdit: true,
    text: 'Головне меню:',
    photo: env.get('MENU_PHOTO_URL'),
    keyboard: global.get('MENU_KB')
});
msg.tgMethod = reply.method;
msg.tgBody = reply.body;
return msg;

function buildReply(o){
  const b = { chat_id: o.chatId, parse_mode: "HTML" };
  if (o.useEdit && o.messageId) b.message_id = o.messageId;
  if (o.useEdit && o.photo) return { method: "editMessageMedia", body: Object.assign(b, { media: { type:"photo", media: o.photo, caption: o.text, parse_mode: "HTML" }, reply_markup: { inline_keyboard: o.keyboard } }) };
  if (o.useEdit) return { method: "editMessageText", body: Object.assign(b, { text: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
  if (o.photo) return { method: "sendPhoto", body: Object.assign(b, { photo: o.photo, caption: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
  return { method: "sendMessage", body: Object.assign(b, { text: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
}
const reply = buildReply({
    chatId: msg.chatId,
    messageId: msg.messageId,
    useEdit: true,
    photo: env.get('MENU_PHOTO_HELP'),
    text: global.get('HELP_TEXT'),
    keyboard: global.get('BACK_KB')
});
msg.tgMethod = reply.method;
msg.tgBody = reply.body;
return msg;

msg.query = `SELECT id, name, TO_CHAR(birthday, 'DD.MM.YYYY') AS birthday_fmt,
(MAKE_DATE(EXTRACT(YEAR FROM CURRENT_DATE)::INT, EXTRACT(MONTH FROM birthday)::INT, EXTRACT(DAY FROM birthday)::INT) - CURRENT_DATE) AS days_until
FROM contacts WHERE owner_id = $1
ORDER BY EXTRACT(MONTH FROM birthday), EXTRACT(DAY FROM birthday)`;
msg.params = [msg.from.id];
return msg;

msg.query = `UPDATE user_sessions SET state='awaiting_name', context='{}'::jsonb WHERE telegram_id=$1`;
msg.params = [msg.from.id];
return msg;

msg.query = `SELECT name, TO_CHAR(birthday, 'DD.MM.YYYY') AS bd,
(MAKE_DATE(EXTRACT(YEAR FROM CURRENT_DATE)::INT, EXTRACT(MONTH FROM birthday)::INT, EXTRACT(DAY FROM birthday)::INT) - CURRENT_DATE) AS days
FROM contacts WHERE owner_id=$1 AND
(MAKE_DATE(EXTRACT(YEAR FROM CURRENT_DATE)::INT, EXTRACT(MONTH FROM birthday)::INT, EXTRACT(DAY FROM birthday)::INT) - CURRENT_DATE) BETWEEN 0 AND 30
ORDER BY days LIMIT 10`;
msg.params = [msg.from.id];
return msg;

const id = msg.callbackData.split(':')[1];
msg.query = `SELECT id, name, TO_CHAR(birthday,'DD.MM.YYYY') AS bd FROM contacts WHERE id=$1 AND owner_id=$2`;
msg.params = [id, msg.from.id];
return msg;

function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
const row = msg.payload && msg.payload[0];
if (!row) {
    msg.tgMethod='editMessageText';
    msg.tgBody={chat_id:msg.chatId,message_id:msg.messageId,text:'Контакт не знайдено.',reply_markup:{inline_keyboard:[[{text:'🏠 Меню',callback_data:'menu_home'}]]}};
    return msg;
}
msg.tgMethod = 'editMessageText';
msg.tgBody = {
    chat_id: msg.chatId,
    message_id: msg.messageId,
    text: `Видалити контакт?\n\n👤 <b>${esc(row.name)}</b>\n🎂 ${row.bd}`,
    parse_mode: 'HTML',
    reply_markup: {
        inline_keyboard: [[
            { text: '🗑 Так, видалити', callback_data: 'del_yes:'+row.id },
            { text: '↩️ Скасувати',    callback_data: 'menu_list' }
        ]]
    }
};
return msg;

const id = msg.callbackData.split(':')[1];
msg.query = `DELETE FROM contacts WHERE id=$1 AND owner_id=$2 RETURNING name`;
msg.params = [id, msg.from.id];
msg.auditAction = 'contact_deleted';
msg.auditEntityType = 'contact';
msg.auditEntityId = Number(id);
return msg;

function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
const row = msg.payload && msg.payload[0];
msg.tgMethod = 'editMessageText';
msg.tgBody = {
    chat_id: msg.chatId,
    message_id: msg.messageId,
    text: row ? `✅ Видалено: <b>${esc(row.name)}</b>` : '⚠️ Контакт не знайдено.',
    parse_mode: 'HTML',
    reply_markup: { inline_keyboard: [[{ text:'📋 До списку', callback_data:'menu_list' },{ text:'🏠 Меню', callback_data:'menu_home' }]] }
};
return [msg, row ? msg : null];

const ctx = msg.session.context;
if (!ctx || !ctx.name || !ctx.date) {
    msg.tgMethod='editMessageText';
    msg.tgBody={chat_id:msg.chatId,message_id:msg.messageId,text:'Щось пішло не так, спробуй ще.',reply_markup:{inline_keyboard:[[{text:'🏠 Меню',callback_data:'menu_home'}]]}};
    return [msg, null];
}
msg._addCtx = ctx;
const interests = ctx.interests || null;
// ON CONFLICT: якщо контакт вже є — UPDATE замість dup-error
msg.query = `INSERT INTO contacts (owner_id, name, birthday, interests) VALUES ($1,$2,$3,$4)
    ON CONFLICT (owner_id, LOWER(name)) DO UPDATE SET birthday=EXCLUDED.birthday, interests=COALESCE(EXCLUDED.interests, contacts.interests), updated_at=NOW()
    RETURNING id, name, TO_CHAR(birthday,'DD.MM.YYYY') AS bd, interests, (xmax = 0) AS was_inserted`;
msg.params = [msg.from.id, ctx.name, ctx.date, interests];
return [null, msg];

msg._saved = msg.payload && msg.payload[0];
msg.query = `UPDATE user_sessions SET state='idle', context=NULL WHERE telegram_id=$1`;
msg.params = [msg.from.id];
return msg;

function esc(s){return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
const r = msg._saved;
msg.tgMethod='editMessageText';
if (!r) {
    msg.tgBody={chat_id:msg.chatId,message_id:msg.messageId,text:'⚠️ Не вдалось зберегти.',reply_markup:{inline_keyboard:[[{text:'🏠 Меню',callback_data:'menu_home'}]]}};
    return [msg, null];
}
const isNew = r.was_inserted !== false;
const verb = isNew ? '✅ Збережено' : '🔄 Оновлено';
msg.tgBody={
    chat_id: msg.chatId, message_id: msg.messageId,
    text: `${verb}: <b>${esc(r.name)}</b> • ${r.bd}\n\n💡 <i>Розкажи про інтереси — AI підкаже ідеї подарунків.</i>`,
    parse_mode:'HTML',
    reply_markup: { inline_keyboard: [
        [{ text:'💡 Додати/змінити інтереси',  callback_data:'interests:'+r.id }],
        [{ text:'🎁 Ідеї подарунків',  callback_data:'gift:'+r.id }],
        [{ text:'➕ Ще один', callback_data:'menu_add' }, { text:'🏠 Меню', callback_data:'menu_home' }]
    ]}
};
msg.auditAction = isNew ? 'contact_added' : 'contact_updated';
msg.auditEntityType = 'contact';
msg.auditEntityId = r.id;
msg.auditPayload = { name: r.name, bd: r.bd };
return [msg, msg];

msg.query = `UPDATE user_sessions SET state='idle', context=NULL WHERE telegram_id=$1`;
msg.params = [msg.from.id];
return msg;

function buildReply(o){
  const b = { chat_id: o.chatId, parse_mode: "HTML" };
  if (o.useEdit && o.messageId) b.message_id = o.messageId;
  if (o.useEdit && o.photo) return { method: "editMessageMedia", body: Object.assign(b, { media: { type:"photo", media: o.photo, caption: o.text, parse_mode: "HTML" }, reply_markup: { inline_keyboard: o.keyboard } }) };
  if (o.useEdit) return { method: "editMessageText", body: Object.assign(b, { text: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
  if (o.photo) return { method: "sendPhoto", body: Object.assign(b, { photo: o.photo, caption: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
  return { method: "sendMessage", body: Object.assign(b, { text: o.text, reply_markup: { inline_keyboard: o.keyboard } }) };
}
const reply = buildReply({
    chatId: msg.chatId,
    messageId: msg.messageId,
    useEdit: true,
    photo: env.get('MENU_PHOTO_URL'),
    text: 'Дію скасовано. Що зробимо далі?',
    keyboard: global.get('MENU_KB')
});
msg.tgMethod = reply.method;
msg.tgBody = reply.body;
return msg;

const cid = msg.callbackData.split(':')[1];
msg.query = `UPDATE user_sessions SET state='awaiting_interests', context=jsonb_build_object('contact_id', $1::bigint) WHERE telegram_id=$2`;
msg.params = [Number(cid), msg.from.id];
return msg;

msg.tgMethod='editMessageText';
msg.tgBody={
    chat_id: msg.chatId, message_id: msg.messageId,
    text: '💡 Що ця людина любить? Розкажи коротко.\n\n<i>Приклади:</i>\n• «любить книги, каву, йога»\n• «фанат футболу, їздить на велосипеді»\n• «дизайнер, цінує мінімалізм»',
    parse_mode:'HTML',
    reply_markup:{ inline_keyboard:[[{text:'⏭ Пропустити',callback_data:'add_cancel'}]] }
};
