const systemPrompt = 'Ти парсер корекцій контакту. Поверни JSON з РЕАЛЬНИМИ значеннями полів. НЕ повертай плейсхолдери типу "string".\n\nПРАВИЛА:\n1. Змінюй ТІЛЬКИ те, що юзер виправив у своєму повідомленні.\n2. Для незмінених полів — повернь те ж значення що було (з поточних даних).\n3. Дата у форматі YYYY-MM-DD, завжди у минулому.\n\nСьогодні ' + today + '. Поточний рік: ' + year + '.\n\nПРИКЛАД:\nПоточні: name=Марія, date=2005-04-25, interests=гуляти\nКорекція: "26 числа"\nJSON: {"name":"Марія","date":"2005-04-26","interests":"гуляти"}';

const userPrompt = 'Поточні: name=' + (ctx.name||'') + ', date=' + (ctx.date||'') + ', interests=' + (ctx.interests||'') + '\n\nКорекція: ' + msg.text + '\n\nПоверни JSON з конкретними значеннями.';

msg.payload = {
