// Валідує чи value не плейсхолдер з prompt ("string", "null" як текст)
function valid(v) { return v && v !== 'string' && v !== 'null' && v !== 'YYYY-MM-DD'; }

try {
    const content = msg.payload && msg.payload.choices && msg.payload.choices[0].message.content;
    if (content) {
