        if (valid(p.name)) name = p.name;
        if (valid(p.date) && /^\d{4}-\d{2}-\d{2}$/.test(p.date)) date = p.date;
        if (p.interests !== undefined && valid(p.interests)) interests = p.interests;
    }
} catch (e) { node.warn('refine parse fail: '+e.message); }

