const t = (msg.text || '').trim();
const tl = t.toLowerCase();
// Стоп-слова — щоб "забудь що я казав" не зматчилось як delete_contact name="що"
const STOP = /^(що|як|де|коли|чому|всіх|всі|усі|мене|тебе|нас|вас|їх|його|її)$/i;

let hit = null;
// nameless intents — детерміновані 100%
if (/^(привіт|вітаю|здоров|добрий день|добрий ранок|добрий вечір|hi|hello)\b/i.test(t))
    hit = { intent: 'greet' };
else if (/^(допомог|поможи|допоможи|як користуват|що ти вмі|що тут робити|help)/i.test(tl))
    hit = { intent: 'help' };
else if (/^(всі|покажи всіх|покажи всі|мої контакти|список|усі контакти)\b/i.test(tl))
    hit = { intent: 'list_all' };
else if (/^(найближч|хто скоро|скоро дн|скоро день народ)/i.test(tl))
    hit = { intent: 'upcoming' };
// delete_contact — verb явний, ім'я сирим (downstream fuzzy match)
else {
    const m = t.match(/^(?:видали|забудь|прибери)\s+([А-ЯҐЄІЇа-яґєії']{2,})\s*$/i);
    if (m && !STOP.test(m[1])) hit = { intent: 'delete_contact', name: m[1] };
}
// show_contact_detail — "про X" / "інфо про X" однозначно про людину
if (!hit) {
    const m = t.match(/^(?:розкажи про|інфо про)\s+([А-ЯҐЄІЇа-яґєії']{2,})\s*$/i);
    if (m && !STOP.test(m[1])) hit = { intent: 'show_contact_detail', name: m[1] };
}

if (hit) {
    msg._intent = { intent: hit.intent, name: hit.name || null, date: null, interests: null, confidence: 1.0 };
    node.warn(`[REGEX INTENT] "${t}" → ${hit.intent}${hit.name ? ' name=' + hit.name : ''}`);
    return [msg, null];
}
return [null, msg];

