function kyivToday() {
    return new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Kyiv' }));
}
function ymd(d) {
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return y + '-' + m + '-' + day;
}
function addDays(d, days) {
    const x = new Date(d);
    x.setDate(x.getDate() + days);
    return x;
}
function hasWord(text, unicodePattern) {
    return new RegExp(unicodePattern, 'i').test(text || '');
}
function relativeBirthdayDate(text, today) {
    const t = (text || '').toLowerCase();
    if (hasWord(t, '\\u043f\\u0456\\u0441\\u043b\\u044f\\u0437\\u0430\\u0432\\u0442\\u0440\\u0430')) return addDays(today, 2);
    if (hasWord(t, '\\u0437\\u0430\\u0432\\u0442\\u0440\\u0430')) return addDays(today, 1);
    if (hasWord(t, '\\u0441\\u044c\\u043e\\u0433\\u043e\\u0434\\u043d\\u0456')) return addDays(today, 0);
    return null;
}
function extractAge(text) {
    const agePattern = '(?:\\u0457\\u0439|\\u0439\\u043e\\u043c\\u0443|\\u0431\\u0443\\u0434\\u0435|\\u0432\\u0438\\u043f\\u043e\\u0432\\u043d\\u0438\\u0442\\u044c\\u0441\\u044f|\\u0432\\u0438\\u043f\\u043e\\u0432\\u043d\\u044e\\u0454\\u0442\\u044c\\u0441\\u044f|\\u0441\\u0442\\u0443\\u043a\\u043d\\u0435)?\\s*(\\d{1,3})\\s*(?:\\u0440\\u0456\\u043a|\\u0440\\u043e\\u043a\\u0438|\\u0440\\u043e\\u043a\\u0456\\u0432|\\u0440\\u043e\\u043a\\u0443)(?=\\s|$|[,.!?;:])';
    const m = String(text || '').match(new RegExp(agePattern, 'i'));
    if (!m) return null;
    const age = Number(m[1]);
    return age >= 0 && age <= 120 ? age : null;
}
function isTurningAgePhrase(text) {
    const turningPattern = '(?:\\u0431\\u0443\\u0434\\u0435|\\u0432\\u0438\\u043f\\u043e\\u0432\\u043d\\u0438\\u0442\\u044c\\u0441\\u044f|\\u0432\\u0438\\u043f\\u043e\\u0432\\u043d\\u044e\\u0454\\u0442\\u044c\\u0441\\u044f|\\u0441\\u0442\\u0443\\u043a\\u043d\\u0435)\\s*\\d{1,3}\\s*(?:\\u0440\\u0456\\u043a|\\u0440\\u043e\\u043a\\u0438|\\u0440\\u043e\\u043a\\u0456\\u0432|\\u0440\\u043e\\u043a\\u0443)(?=\\s|$|[,.!?;:])';
    return new RegExp(turningPattern, 'i').test(String(text || ''));
}

if (intent === 'add_contact') {
    const text = msg._userText || msg.text || '';
    const age = extractAge(text);
    const today = kyivToday();
    const target = relativeBirthdayDate(text, today);
    if (age !== null && target) {
        const todayYmd = ymd(today);
        const targetYmd = ymd(target);
        const targetIsFuture = targetYmd > todayYmd;
        const turningAge = isTurningAgePhrase(text) ? age : age + (targetIsFuture ? 1 : 0);
        const birthYear = target.getFullYear() - turningAge;
        date = birthYear + '-' + String(target.getMonth() + 1).padStart(2, '0') + '-' + String(target.getDate()).padStart(2, '0');
        confidence = Math.max(confidence, 0.9);
        msg._dateCorrected = { reason: 'relative_age_birthday', age, turningAge, target: targetYmd, date };
    }
}

