function detectGender(n) {
    const clean = (n || '').trim().toLowerCase();
    if (!clean) return 'unknown';
    const male = ['петро','петра','іван','івана','олександр','саша','дмитро','дмитра','сергій','андрій','юрій','тарас','тараса','богдан','микола','миколи','володимир','володя','віктор','роман','назар','олег','василь','павло','степан','михайло','миша','артем','максим','денис','ярослав','ігор','віталій','антон','валентин','костянтин','кость','костя','александр','нікіта'];
    const female = ['оля','ольга','марія','катерина','катя','ірина','іра','анна','аня','юлія','юля','наталія','наталя','тетяна','таня','світлана','вікторія','віка','оксана','христина','віра','галина','валентина','валя','людмила','ніна','олена','лена','лариса','анастасія','настя','софія','марина','маргарита','маша','даша','дарина','діана','аліна'];
    if (male.includes(clean)) return 'male';
    if (female.includes(clean)) return 'female';
    if (/[^аеіиоуюяїй]$/i.test(clean)) return 'male';
    if (/[ой]$/i.test(clean)) return 'male';
    return 'unknown';
}

const gender = detectGender(name);
